package ch03.ex1;
// 부호 연산자 +,-
// + : 현재 부호 유지
// - : 현재 부호 변경
public class OpEx05 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int x = -10;
		System.out.println("+x=" + +x);
		System.out.println("-x=" + -x);
		
		x = 10;
		System.out.println("+x=" + +x);
		System.out.println("-x=" + -x);
	}

}
